// Run via: cd studio && npx sanity exec scripts/apply-asset-patches.mjs --with-user-token
//
// Reads the NDJSON of asset patches generated by
// scripts/enrich-asset-metadata.mjs (../tmp/enrich-asset-patches.ndjson) and
// applies each as a granular Sanity patch using the CLI user's auth.
//
// Why this exists: `sanity dataset import --replace` rejects asset-type docs
// because they're missing immutable asset properties (assetId, sha1hash, etc).
// The client.patch() API doesn't care about that, but using the SANITY_API_WRITE_TOKEN
// directly hit a "project user not found" membership error. The CLI exec
// context uses the Sanity CLI's bundled user session (Nathan's Administrator
// account), which has full project membership and can patch anything.
//
// Batched via client.transaction() — 172 patches go up as one request.

import { getCliClient } from 'sanity/cli';
import { readFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ndjsonPath = resolve(__dirname, '..', '..', 'tmp', 'enrich-asset-patches.ndjson');

const client = getCliClient({ apiVersion: '2025-02-19' });

const docs = readFileSync(ndjsonPath, 'utf-8')
  .trim()
  .split('\n')
  .map((line) => JSON.parse(line));

console.log(`Loaded ${docs.length} asset patches from ${ndjsonPath}`);

// Build one transaction with all patches.
let tx = client.transaction();
for (const doc of docs) {
  tx = tx.patch(doc._id, (p) =>
    p.set({
      title: doc.title,
      altText: doc.altText,
      description: doc.description,
      opt: doc.opt,
    }),
  );
}

console.log(`Committing transaction with ${docs.length} patches...`);
const result = await tx.commit({ autoGenerateArrayKeys: true });
console.log(`Done. Server returned transaction id: ${result.transactionId}`);
console.log(`Mutated ${result.results.length} assets.`);
